// src/components/ImpressaoListaAgendamentos.js

import React from "react";

const ImpressaoListaAgendamentos = ({
  agendamentos = [],
  disciplinaNome = "",
  semestre = "",
  dataDisciplina = ""
}) => {
  return (
    <div id="area-impressao" className="p-8">
      <h1 className="text-2xl font-bold mb-2 print:text-black">
        Lista de Pacientes - {disciplinaNome} ({semestre})
      </h1>
      <div className="mb-6 text-lg text-gray-600 print:text-black">
        Data: {dataDisciplina}
      </div>
      <table className="min-w-full border border-gray-300 print:text-black">
        <thead>
          <tr className="bg-gray-100">
            <th className="border px-3 py-2"></th>
            <th className="border px-3 py-2">Operador</th>
            <th className="border px-3 py-2">Auxiliar</th>
            <th className="border px-3 py-2">Disciplina</th>
            <th className="border px-3 py-2">Paciente</th>
            <th className="border px-3 py-2">Telefone</th>
            <th className="border px-3 py-2">Status</th>
          </tr>
        </thead>
        <tbody>
          {agendamentos.map((ag, idx) => (
            <tr key={ag.id || idx}>
              <td className="border px-3 py-2">{idx + 1}</td>
              <td className="border px-3 py-2">{ag.operadorNome}</td>
              <td className="border px-3 py-2">{ag.auxiliarNome}</td>
              <td className="border px-3 py-2">{ag.disciplinaNome}</td>
              <td className="border px-3 py-2">{ag.pacienteNome}</td>
              <td className="border px-3 py-2">{ag.telefone}</td>
              <td className="border px-3 py-2">{ag.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ImpressaoListaAgendamentos;
